SELECT variant_name, description
FROM variants
WHERE transmissibility > 0.5;

SELECT variant_name, transmissibility, severity, vaccine_effectiveness
FROM variants
ORDER BY transmissibility DESC;

SELECT SUM(count) AS total_cases
FROM variant_cases
WHERE variant_id = 1;

SELECT total 
FROM variant_cases 
WHERE variant_id = 1 AND date = '2023-03-15';

SELECT AVG(hospitalization_rate) AS average_hospitalization_rate
FROM variant_cases
WHERE count > 500;
